typescriptInterfaces:
// ==================== TypeScript Interfaces for SMP Cell ====================

/**
 * SMP Cell - A locked static program combining Seed + Model + Prompt
 * All three components combine to create a deterministic, reproducible AI program
 */
export interface SMPCell {
  id: string;
  version: string;
  seed: Seed;
  model: Model;
  prompt: Prompt;
  metadata: Metadata;
  lockStatus: LockStatus;
  fingerprint?: Fingerprint;
  extensions?: Record<string, unknown>;
}

/**
 * Seed - Initial state/deterministic starting point
 * Ensures reproducibility of the SMP cell execution
 */
export interface Seed {
  type: 'numeric' | 'tensor' | 'state_vector' | 'configuration' | 'embedding' | 'hybrid';
  value: number | number[] | Record<string, unknown> | string;
  entropy: number;
  derivationPath?: string;
  salt?: string;
  initializedAt?: string;
}

/**
 * Model - AI model configuration
 */
export interface Model {
  provider: 'openai' | 'anthropic' | 'google' | 'meta' | 'mistral' | 'cohere' | 'local' | 'custom';
  modelName: string;
  modelId?: string;
  parameters: ModelParameters;
  capabilities?: ('text' | 'code' | 'reasoning' | 'multimodal' | 'function_calling' | 'streaming' | 'batch')[];
  constraints?: ModelConstraints;
  fineTuning?: FineTuningConfig;
}

export interface ModelParameters {
  temperature?: number;
  topP?: number;
  topK?: number;
  maxTokens?: number;
  frequencyPenalty?: number;
  presencePenalty?: number;
  stopSequences?: string[];
  seed?: number;
  responseFormat?: ResponseFormat;
}

export interface ResponseFormat {
  type: 'text' | 'json_object' | 'json_schema';
  schema?: Record<string, unknown>;
}

export interface ModelConstraints {
  maxTokens?: number;
  contextWindow?: number;
  rateLimit?: number;
  costPerToken?: number;
}

export interface FineTuningConfig {
  baseModel?: string;
  checkpointId?: string;
  adapterWeights?: string;
}

/**
 * Prompt - Template and variables for task definition
 */
export interface Prompt {
  template: string;
  variables: Record<string, PromptVariable>;
  systemPrompt?: string;
  examples?: PromptExample[];
  constraints?: PromptConstraints;
}

export interface PromptVariable {
  type: 'string' | 'number' | 'boolean' | 'array' | 'object' | 'context' | 'file' | 'url';
  description: string;
  default?: unknown;
  required?: boolean;
  validation?: VariableValidation;
  transform?: string;
}

export interface VariableValidation {
  pattern?: string;
  minLength?: number;
  maxLength?: number;
  min?: number;
  max?: number;
  enum?: unknown[];
}

export interface PromptExample {
  input: Record<string, unknown>;
  output: string;
}

export interface PromptConstraints {
  requiredVariables?: string[];
  validationRules?: string[];
}

/**
 * Metadata for SMP cell documentation
 */
export interface Metadata {
  name?: string;
  description?: string;
  author?: string;
  createdAt?: string;
  updatedAt?: string;
  tags?: string[];
  category?: string;
  license?: string;
  checksum?: string;
}

/**
 * LockStatus - Immutability control
 */
export interface LockStatus {
  status: 'unlocked' | 'partial' | 'locked' | 'frozen';
  lockedAt: string;
  lockedBy?: string;
  lockHash?: string;
  unlockConditions?: string[];
}

/**
 * Fingerprint - Cryptographic verification
 */
export interface Fingerprint {
  algorithm?: string;
  hash?: string;
  seedHash?: string;
  modelHash?: string;
  promptHash?: string;
  computedAt?: string;
}

// ==================== Utility Types ====================

export type SMPCellStatus = 'unlocked' | 'partial' | 'locked' | 'frozen';
export type SeedType = 'numeric' | 'tensor' | 'state_vector' | 'configuration' | 'embedding' | 'hybrid';
export type ModelProvider = 'openai' | 'anthropic' | 'google' | 'meta' | 'mistral' | 'cohere' | 'local' | 'custom';

/**
 * Factory type for creating SMP cells with required defaults
 */
export interface SMPCellFactory {
  create(config: Partial<SMPCell>): SMPCell;
  lock(cell: SMPCell): SMPCell;
  verify(cell: SMPCell): boolean;
  derive(parent: SMPCell, modifications: Partial<SMPCell>): SMPCell;
}

